def hotp(secret: str, counter: int, digits: int = 6, algorithm: str = "SHA1") -> str:
    algo = algorithm.upper()
    if algo == "SHA1":
        digestmod = hashlib.sha1
    elif algo == "SHA256":
        digestmod = hashlib.sha256
    elif algo == "SHA512":
        digestmod = hashlib.sha512
    else:
        raise ValueError("Unsupported algorithm")

    key = _b32_normalize(secret)
    msg = counter.to_bytes(8, "big")
    h = hmac.new(key, msg, digestmod).digest()
    offset = h[-1] & 0x0F
    code_int = (
        ((h[offset] & 0x7F) << 24)
        | ((h[offset + 1] & 0xFF) << 16)
        | ((h[offset + 2] & 0xFF) << 8)
        | (h[offset + 3] & 0xFF)
    )
    code = code_int % (10 ** digits)
    return str(code).zfill(digits)


def totp(
    secret: str,
    timestamp: Optional[int] = None,
    period: int = 30,
    digits: int = 6,
    algorithm: str = "SHA1",
) -> str:
    if timestamp is None:
        timestamp = int(time.time())
    counter = int(timestamp // period)
    return hotp(secret, counter, digits=digits, algorithm=algorithm)


def verify_totp(
    secret: str,
    code: str,
    timestamp: Optional[int] = None,
    period: int = 30,
    digits: int = 6,
    algorithm: str = "SHA1",
    window: int = 1,
) -> bool:
    if timestamp is None:
        timestamp = int(time.time())
    normalized_code = str(code).strip().replace(" ", "")
    if not normalized_code.isdigit() or len(normalized_code) != digits:
        return False

    current_counter = int(timestamp // period)
    for offset in range(-window, window + 1):
        expected = hotp(secret, current_counter + offset, digits=digits, algorithm=algorithm)
        if hmac.compare_digest(expected, normalized_code):
            return True
    return False


def build_otpauth_uri(
    secret: str,
    account_name: str,
    issuer: str,
    period: int = 30,
    digits: int = 6,
    algorithm: str = "SHA1",
) -> str:
    label = f"{issuer}:{account_name}"
    encoded_label = urllib.parse.quote(label)
    params = {
        "secret": secret,
        "issuer": issuer,
        "algorithm": algorithm.upper(),
        "digits": str(digits),
        "period": str(period),
    }
    return f"otpauth://totp/{encoded_label}?{urllib.parse.urlencode(params)}"


def create_qr_code_png_bytes(data: str, box_size: int = 10, border: int = 4) -> bytes:
    if qrcode is None:
        raise RuntimeError("qrcode package is required to generate QR codes")
    qr = qrcode.QRCode(
        version=None,
        error_correction=qrcode.constants.ERROR_CORRECT_M,
        box_size=box_size,
        border=border,
    )
    qr.add_data(data)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    return buf.getvalue()


def save_qr_code_png(data: str, file_path: str, box_size: int = 10, border: int = 4) -> str:
    png = create_qr_code_png_bytes(data, box_size=box_size, border=border)
    os.makedirs(os.path.dirname(file_path) or ".", exist_ok=True)
    with open(file_path, "wb") as f:
        f.write(png)
    return file_path


